arguments.prompt:
You are working in /tmp/sv-057cfbd216714a54b0c791ee67f88bbe/ShipmentTracker which is a Blazor Web App solution with Interactive Auto, Global interactivity and Individual authentication already scaffolded.

The solution has:
- `ShipmentTracker/` (server project)
- `ShipmentTracker.Client/` (WebAssembly client project)

The server Program.cs already has EF Core with SQLite, ASP.NET Core Identity, and all the Blazor render modes configured.

## Your Task

Implement a logistics shipment tracking app. Do the following:

### 1. Remove default template pages
Delete these files:
- `ShipmentTracker.Client/Pages/Counter.razor`
- `ShipmentTracker.Client/Pages/Weather.razor`

### 2. Create shared models in the Client project

Create `ShipmentTracker.Client/Models/Shipment.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public string RecipientName { get; set; } = string.Empty;
    public string RecipientEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}
```

### 3. Create a service interface in the Client project

Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<Shipment?> UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus);
}
```

### 4. Create the Client-side HTTP implementation

Create `ShipmentTracker.Client/Services/ShipmentHttpService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

public class ShipmentHttpService : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentHttpService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await _http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await _http.GetFromJsonAsync<Shipment?>($"api/shipments/track/{trackingNumber}");
    }

    public async Task<Shipment?> UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        var response = await _http.PutAsJsonAsync($"api/shipments/{id}/status", newStatus);
        if (response.IsSuccessStatusCode)
            return await response.Content.ReadFromJsonAsync<Shipment>();
        return null;
    }
}
```

### 5. Register HttpClient and the service in Client Program.cs

Edit `ShipmentTracker.Client/Program.cs` to register:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddScoped(sp => new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<IShipmentService, ShipmentHttpService>();

await builder.Build().RunAsync();
```

### 6. Create the server-side service implementation

Create `ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
namespace ShipmentTracker.Services;

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

public class ShipmentServerService : IShipmentService
{
    private readonly ApplicationDbContext _db;

    public ShipmentServerService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await _db.Shipments.OrderByDescending(s => s.ShippedDate).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await _db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    }

    public async Task<Shipment?> UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = await _db.Shipments.FindAsync(id);
        if (shipment is null) return null;
        shipment.Status = newStatus;
        await _db.SaveChangesAsync();
        return shipment;
    }
}
```

### 7. Add Shipments DbSet to ApplicationDbContext

Edit `ShipmentTracker/Data/ApplicationDbContext.cs` to add:
```csharp
using ShipmentTracker.Client.Models;
```
and inside the class:
```csharp
public DbSet<Shipment> Shipments => Set<Shipment>();
```

### 8. Create API endpoints and register the server service

Edit `ShipmentTracker/Program.cs`. Add these usings at the top:
```csharp
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Services;
```

After the existing service registrations (after `AddSingleton<IEmailSender...>`), add:
```csharp
builder.Services.AddScoped<IShipmentService, ShipmentServerService>();
```

Before `app.Run();`, add the API endpoints:
```csharp
// Shipment API endpoints
var shipmentApi = app.MapGroup("api/shipments").RequireAuthorization();

shipmentApi.MapGet("/", async (IShipmentService service) =>
    Results.Ok(await service.GetAllShipmentsAsync()));

shipmentApi.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
{
    var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
    return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
});

shipmentApi.MapPut("/{id}/status", async (int id, ShipmentStatus newStatus, IShipmentService service) =>
{
    var shipment = await service.UpdateShipmentStatusAsync(id, newStatus);
    return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
});
```

