@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher - Shipments</PageTitle>

<h2>Shipment Dashboard</h2>

@if (_loading)
{
