namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime ShippedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public string RecipientName { get; set; } = string.Empty;
    public string RecipientEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}

namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<Shipment?> UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus);
}

namespace ShipmentTracker.Client.Services;

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

public class ShipmentHttpService : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentHttpService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await _http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await _http.GetFromJsonAsync<Shipment?>($"api/shipments/track/{trackingNumber}");
    }

    public async Task<Shipment?> UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        var response = await _http.PutAsJsonAsync($"api/shipments/{id}/status", newStatus);
        if (response.IsSuccessStatusCode)
            return await response.Content.ReadFromJsonAsync<Shipment>();
        return null;
    }
}

namespace ShipmentTracker.Services;

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

public class ShipmentServerService : IShipmentService
{
    private readonly ApplicationDbContext _db;

    public ShipmentServerService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await _db.Shipments.OrderByDescending(s => s.ShippedDate).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await _db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    }

    public async Task<Shipment?> UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = await _db.Shipments.FindAsync(id);
        if (shipment is null) return null;
        shipment.Status = newStatus;
        await _db.SaveChangesAsync();
        return shipment;
    }
}

@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher - Shipments</PageTitle>

<h2>Shipment Dashboard</h2>

@if (_loading)
{
    <p><em>Loading shipments...</em></p>
}
else if (_shipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="_filterText" @bind:event="oninput" />
    </div>

    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>ETA</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.ShippedDate.ToString("MMM dd, yyyy")</td>
                    <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                @onchange="(e) => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status" selected="@(status == shipment.Status)">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment> _shipments = [];
    private bool _loading = true;
    private string _filterText = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        string.IsNullOrWhiteSpace(_filterText)
            ? _shipments
            : _shipments.Where(s => s.Destination.Contains(_filterText, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        _shipments = await ShipmentService.GetAllShipmentsAsync();
        _loading = false;
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var updated = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            if (updated is not null)
            {
                shipment.Status = updated.Status;
            }
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-001-2026)"
                   @bind="_trackingNumber" @onkeyup="HandleKeyUp" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@_searching">
                @if (_searching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (_searched && _shipment is null)
{
    <div class="alert alert-warning">
        No shipment found with tracking number <strong>@_searchedNumber</strong>.
    </div>
}
else if (_shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <strong>@_shipment.TrackingNumber</strong> — @_shipment.Description
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(_shipment.Status) fs-6">@_shipment.Status</span></dd>

                        <dt>Origin</dt>
                        <dd>@_shipment.Origin</dd>

                        <dt>Destination</dt>
                        <dd>@_shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@_shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>

                        <dt>Estimated Delivery</dt>
                        <dd class="fs-5 fw-bold text-primary">@_shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")</dd>

                        <dt>Recipient</dt>
                        <dd>@_shipment.RecipientName</dd>
                    </dl>
                </div>
            </div>

            @{
                var progress = GetProgressPercentage(_shipment.Status);
            }
            <div class="mt-3">
                <label class="form-label">Delivery Progress</label>
                <div class="progress" style="height: 25px;">
                    <div class="progress-bar @GetProgressBarClass(_shipment.Status)"
                         role="progressbar" style="width: @progress%"
                         aria-valuenow="@progress" aria-valuemin="0" aria-valuemax="100">
                        @progress%
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string _trackingNumber = string.Empty;
    private string _searchedNumber = string.Empty;
