    private bool _searched;
    private bool _searching;

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(_trackingNumber)) return;

        _searching = true;
        _searchedNumber = _trackingNumber.Trim();
        _shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(_searchedNumber);
        _searched = true;
        _searching = false;
    }

    private async Task HandleKeyUp(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private static int GetProgressPercentage(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        _ => 0
    };

